func Uglify(in string) string {
	if path.Ext(in) == "" {
		if len(in) < 2 {
			return "/"
		}

		return path.Clean(in) + ".html"
	}

	name, ext := fileAndExt(in, pb)
	if name == "index" {

		d := path.Dir(in)
		if len(d) > 1 {
			return d + ext
		}
		return in
	}

	if name == "" {
		return path.Dir(in) + "index" + ext
	}

	return path.Clean(in)
}
